// MARK: - 3. WalletManager (ViewModel/Service Layer)
// Manages the collection of wallets, interacts with CryptoManager and KeychainService.
class WalletManager: ObservableObject {
    @Published var wallets: [Wallet] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private var privateKeyStorePrefix = "private_key_"

    init() {
        loadWallets()
    }

    func createWallet(name: String, currency: String) -> Wallet? {
        isLoading = true
        errorMessage = nil
        do {
            let privateKey = CryptoManager.shared.generatePrivateKey()
            let publicKey = CryptoManager.shared.derivePublicKey(privateKey: privateKey)
            let address = CryptoManager.shared.deriveAddress(publicKey: publicKey, currency: currency)

            let newWallet = Wallet(id: UUID(), name: name, address: address, currency: currency)

            // Save private key securely
            let saveStatus = KeychainService.shared.save(key: privateKeyStorePrefix + newWallet.id.uuidString, data: privateKey)
            guard saveStatus == errSecSuccess else {
                print("Failed to save private key to Keychain: \(saveStatus)")
                errorMessage = "Failed to secure private key."
                isLoading = false
                return nil
            }

            wallets.append(newWallet)
            saveWalletsMetadata() // Save wallet metadata (excluding private key)
            isLoading = false
            return newWallet
        } catch {
            errorMessage = "Failed to create wallet: \(error.localizedDescription)"
            isLoading = false
            return nil
        }
    }

    func deleteWallet(walletId: UUID) {
        isLoading = true
        errorMessage = nil
        wallets.removeAll { $0.id == walletId }
        _ = KeychainService.shared.delete(key: privateKeyStorePrefix + walletId.uuidString)
        saveWalletsMetadata()
        isLoading = false
    }

    func loadWallets() {
        isLoading = true
        errorMessage = nil
        if let data = UserDefaults.standard.data(forKey: "savedWallets") {
            do {
                let decodedWallets = try JSONDecoder().decode([Wallet].self, from: data)
                self.wallets = decodedWallets
            } catch {
                errorMessage = "Failed to decode saved wallets: \(error.localizedDescription)"
                print("Failed to decode saved wallets: \(error)")
            }
        }
        isLoading = false
    }

    private func saveWalletsMetadata() {
        do {
            let data = try JSONEncoder().encode(wallets)
            UserDefaults.standard.set(data, forKey: "savedWallets")
        } catch {
            errorMessage = "Failed to save wallets metadata: \(error.localizedDescription)"
            print("Failed to encode wallets metadata: \(error)")
        }
    }

    func getPrivateKey(for wallet: Wallet) throws -> Data {
        guard let privateKeyData = KeychainService.shared.load(key: privateKeyStorePrefix + wallet.id.uuidString) else {
            throw WalletError.privateKeyNotFound
        }
        return privateKeyData
    }

    func sendTransaction(from wallet: Wallet, toAddress: String, amount: Decimal) async throws -> String {
        isLoading = true
        errorMessage = nil
        do {
            let privateKey = try getPrivateKey(for: wallet)

            // --- Construct Raw Transaction Data (Highly Simplified for MVP) ---
            // In a real app, this step is complex:
            // 1. Fetch current nonce/UTXOs for the 'from' address.
            // 2. Build the specific transaction structure for the currency (e.g., BTC raw transaction, ETH EIP-1559 transaction).
            // 3. Calculate appropriate gas/fee.
            // 4. Hash the transaction data for signing.

            // MVP Placeholder: Just hash some basic info for signing
            let transactionDataString = "from:\(wallet.address)-to:\(toAddress)-amount:\(amount)-date:\(Date().timeIntervalSince1970)"
            let transactionHash = SHA256.hash(data: transactionDataString.data(using: .utf8)!)
            let transactionHashData = Data(transactionHash)

            // Sign the transaction hash
            let signature = try CryptoManager.shared.sign(data: transactionHashData, privateKey: privateKey)

            // --- Combine hash and signature into a "raw transaction" for broadcasting ---
            // This is NOT how real raw transactions are structured.
            // A real raw transaction would be the *signed, serialized transaction data*.
            let rawTransaction = transactionHashData + signature

            // Broadcast the transaction
            let txId = try await BlockchainService.shared.sendTransaction(rawTransaction: rawTransaction, currency: wallet.currency)

            // Optionally, update local wallet state or show a success message
            print("Transaction sent successfully with ID: \(txId)")
            isLoading = false
            return txId

        } catch {
            errorMessage = "Transaction failed: \(error.localizedDescription)"
            isLoading = false
            throw error // Re-throw for UI to handle specific errors
        }
    }

    enum WalletError: Error, LocalizedError {
        case privateKeyNotFound
        var errorDescription: String? {
            switch self {
            case .privateKeyNotFound: return "Private key not found for this wallet."
            }
        }
    }
}

