// Main App Structure
@main
struct CryptoWalletApp: App {
    @StateObject var walletManager = WalletManager()

    var body: some Scene {
        WindowGroup {
            ContentView()
                .environmentObject(walletManager)
        }
    }
}

// Main View - Lists Wallets
struct ContentView: View {
    @EnvironmentObject var walletManager: WalletManager
    @State private var showingCreateWalletSheet = false

    var body: some View {
        NavigationView {
            List {
                if walletManager.wallets.isEmpty {
                    Text("No wallets created yet. Tap '+' to add one.")
                        .foregroundColor(.gray)
                } else {
                    ForEach(walletManager.wallets) { wallet in
                        NavigationLink(destination: WalletDetailView(wallet: wallet)) {
                            WalletRow(wallet: wallet)
                        }
                    }
                    .onDelete(perform: deleteWallet)
                }
            }
            .navigationTitle("My Wallets")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button {
                        showingCreateWalletSheet = true
                    } label: {
                        Image(systemName: "plus.circle.fill")
                    }
                }
            }
            .sheet(isPresented: $showingCreateWalletSheet) {
                CreateWalletView(isShowingSheet: $showingCreateWalletSheet)
                    .environmentObject(walletManager)
            }
            .overlay {
                if walletManager.isLoading {
                    ProgressView("Loading...")
                        .padding()
                        .background(Color.gray.opacity(0.8))
                        .cornerRadius(10)
                }
            }
            .alert("Error", isPresented: .constant(walletManager.errorMessage != nil)) {
                Button("OK") { walletManager.errorMessage = nil }
            } message: {
                Text(walletManager.errorMessage ?? "An unknown error occurred.")
            }
        }
    }

    private func deleteWallet(at offsets: IndexSet) {
        offsets.forEach { index in
            let walletToDelete = walletManager.wallets[index]
            walletManager.deleteWallet(walletId: walletToDelete.id)
        }
    }
}

// Wallet List Row
struct WalletRow: View {
    let wallet: Wallet
    @State private var balance: Decimal?
    @State private var isLoadingBalance = false
    @State private var errorMessage: String?

    var body: some View {
        VStack(alignment: .leading) {
            Text(wallet.name)
                .font(.headline)
            Text(wallet.address)
                .font(.caption)
                .foregroundColor(.gray)
                .lineLimit(1)
            HStack {
                Text(wallet.currency)
                    .font(.caption2)
                    .padding(.horizontal, 6)
                    .padding(.vertical, 3)
                    .background(Color.blue.opacity(0.2))
                    .cornerRadius(5)
                Spacer()
                if isLoadingBalance {
                    ProgressView()
                } else if let balance = balance {
                    Text("\(balance.formatted(.number.precision(.fractionLength(4)))) BTC") // Assuming BTC for demo
                        .font(.subheadline)
                        .fontWeight(.medium)
                } else {
                    Text("Balance: N/A")
                        .font(.subheadline)
                        .foregroundColor(.red)
                }
            }
        }
        .padding(.vertical, 4)
        .task {
            await fetchBalance()
        }
    }

    private func fetchBalance() async {
        isLoadingBalance = true
        errorMessage = nil
        do {
            self.balance = try await BlockchainService.shared.getBalance(address: wallet.address, currency: wallet.currency)
        } catch {
            errorMessage = error.localizedDescription
            print("Failed to fetch balance: \(error)")
        }
        isLoadingBalance = false
    }
}

// Wallet Detail View
struct WalletDetailView: View {
    @EnvironmentObject var walletManager: WalletManager
    let wallet: Wallet

    @State private var balance: Decimal?
    @State private var transactions: [Transaction] = []
    @State private var isLoadingDetails = false
    @State private var errorMessage: String?
    @State private var showingSendSheet = false

    var body: some View {
        List {
            Section("Wallet Info") {
                HStack {
                    Text("Name")
                    Spacer()
                    Text(wallet.name)
                }
                HStack {
                    Text("Address")
                    Spacer()
                    Text(wallet.address)
                        .font(.caption)
                        .lineLimit(1)
                    Button {
                        UIPasteboard.general.string = wallet.address
                    } label: {
                        Image(systemName: "doc.on.doc")
                    }
                }
                HStack {
                    Text("Currency")
                    Spacer()
                    Text(wallet.currency)
                }
                HStack {
                    Text("Balance")
                    Spacer()
                    if isLoadingDetails {
                        ProgressView()
                    } else if let balance = balance {
                        Text("\(balance.formatted(.number.precision(.fractionLength(4)))) BTC")
                    } else {
                        Text("N/A")
                            .foregroundColor(.red)
                    }
                }
            }

            Section("Actions") {
                Button("Send \(wallet.currency)") {
                    showingSendSheet = true
                }
            }

            Section("Transactions") {
                if isLoadingDetails {
                    ProgressView("Loading transactions...")
                } else if transactions.isEmpty {
                    Text("No transactions found.")
                        .foregroundColor(.gray)
                } else {
                    ForEach(transactions) { tx in
                        VStack(alignment: .leading) {
                            HStack {
                                Text(tx.id.uuidString.prefix(8) + "...")
                                Spacer()
                                Text("\(tx.amount.formatted(.number.precision(.fractionLength(4)))) BTC")
                                    .fontWeight(.medium)
                                    .foregroundColor(tx.fromAddress == wallet.address ? .red : .green)
                            }
                            Text("To: \(tx.toAddress.prefix(10))...")
                                .font(.caption)
                                .foregroundColor(.gray)
                            Text("Status: \(tx.status.capitalized)")
                                .font(.caption2)
                                .foregroundColor(tx.status == "confirmed" ? .green : .orange)
                        }
                    }
                }
            }
        }
        .navigationTitle(wallet.name)
        .onAppear(perform: refreshDetails) // Call refreshDetails when the view appears
        .refreshable { // iOS 15+ pull-to-refresh
            refreshDetails()
        }
        .sheet(isPresented: $showingSendSheet) {
            SendTransactionView(wallet: wallet, isShowingSheet: $showingSendSheet)
                .environmentObject(walletManager)
        }
        .overlay {
            if walletManager.isLoading { // Show global loading from WalletManager
                ProgressView("Processing...")
                    .padding()
                    .background(Color.gray.opacity(0.8))
                    .cornerRadius(10)
            }
        }
        .alert("Error", isPresented: .constant(errorMessage != nil)) {
            Button("OK") { errorMessage = nil }
        } message: {
            Text(errorMessage ?? "An unknown error occurred.")
        }
    }

    private func refreshDetails() {
        Task {
            isLoadingDetails = true
            errorMessage = nil
            do {
                async let fetchedBalance = BlockchainService.shared.getBalance(address: wallet.address, currency: wallet.currency)
                async let fetchedTransactions = BlockchainService.shared.getTransactions(address: wallet.address, currency: wallet.currency)

                self.balance = try await fetchedBalance
                self.transactions = try await fetchedTransactions.sorted(by: { $0.date > $1.date })
            } catch {
                errorMessage = error.localizedDescription
                print("Failed to fetch wallet details: \(error)")
            }
            isLoadingDetails = false
        }
    }
}


// Create New Wallet View
struct CreateWalletView: View {
    @EnvironmentObject var walletManager: WalletManager
    @Binding var isShowingSheet: Bool

    @State private var walletName: String = ""
    @State private var selectedCurrency: String = "Bitcoin Testnet" // MVP, could be an enum later
    private let availableCurrencies = ["Bitcoin Testnet", "Ethereum Sepolia"]

    var body: some View {
        NavigationView {
            Form {
                Section("Wallet Details") {
                    TextField("Wallet Name", text: $walletName)
                    Picker("Currency", selection: $selectedCurrency) {
                        ForEach(availableCurrencies, id: \.self) { currency in
                            Text(currency).tag(currency)
                        }
                    }
                }

                Section {
                    Button("Create Wallet") {
                        if !walletName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                            _ = walletManager.createWallet(name: walletName, currency: selectedCurrency)
                            isShowingSheet = false
                        } else {
                            walletManager.errorMessage = "Wallet name cannot be empty."
                        }
                    }
                    .disabled(walletName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || walletManager.isLoading)
                }
            }
            .navigationTitle("New Wallet")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") {
                        isShowingSheet = false
                    }
                }
            }
            .overlay {
                if walletManager.isLoading {
                    ProgressView("Creating wallet...")
                        .padding()
                        .background(Color.gray.opacity(0.8))
                        .cornerRadius(10)
                }
            }
        }
    }
}

// Send Transaction View
struct SendTransactionView: View {
    @EnvironmentObject var walletManager: WalletManager
    let wallet: Wallet
    @Binding var isShowingSheet: Bool

    @State private var recipientAddress: String = ""
    @State private var amountString: String = "" // Use string for input, convert to Decimal
    @State private var transactionInProgress: Bool = false

    var body: some View {
        NavigationView {
            Form {
                Section("From Wallet") {
                    Text(wallet.name)
                        .font(.headline)
                    Text(wallet.address)
                        .font(.caption)
                }

                Section("Transaction Details") {
                    TextField("Recipient Address", text: $recipientAddress)
                    TextField("Amount", text: $amountString)
                        .keyboardType(.decimalPad)
                }

                Section {
                    Button("Send Transaction") {
                        Task {
                            await sendTransaction()
                        }
                    }
                    .disabled(recipientAddress.isEmpty || amountString.isEmpty || transactionInProgress)
                }
            }
            .navigationTitle("Send \(wallet.currency)")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") {
                        isShowingSheet = false
                    }
                }
            }
            .overlay {
                if transactionInProgress {
                    ProgressView("Sending transaction...")
                        .padding()
                        .background(Color.gray.opacity(0.8))
                        .cornerRadius(10)
                }
            }
            .alert("Error", isPresented: .constant(walletManager.errorMessage != nil)) {
                Button("OK") { walletManager.errorMessage = nil }
            } message: {
                Text(walletManager.errorMessage ?? "An unknown error occurred.")
            }
        }
    }

    private func sendTransaction() async {
        transactionInProgress = true
        walletManager.errorMessage = nil // Clear previous errors

        guard let amount = Decimal(string: amountString), amount > 0 else {
            walletManager.errorMessage = "Please enter a valid amount."
            transactionInProgress = false
            return
        }

        guard !recipientAddress.isEmpty else {
            walletManager.errorMessage = "Recipient address cannot be empty."
            transactionInProgress = false
            return
        }

        do {
            _ = try await walletManager.sendTransaction(from: wallet, toAddress: recipientAddress, amount: amount)
            isShowingSheet = false // Dismiss sheet on success
        } catch {
            // Error handled by walletManager, just update local state
        }
        transactionInProgress = false
    }
}